{%- comment -%} BRANCH PAGE: Generate JavaScript branch→periods mapping for client-side filtering {%- endcomment -%}

{%- if page.title == 'Branch' -%}
<script>
// Branch → Periods mapping for dynamic period dropdown population
console.log('DEBUG: Creating branch periods mapping...');
console.log('DEBUG: branchPeriodsMapping query size:', {{branchPeriodsMapping.results.entities.size | default: 0}});


{%- if branchPeriodsMapping.results.entities.size > 0 -%}
window.branchPeriodsMapping = {
{%- assign processedBranches = "" -%}
{%- assign allPeriodsForUser = "" -%}
{%- for row in branchPeriodsMapping.results.entities -%}
    {%- if row.branchid -%}
        {%- assign branchGuid = row.branchid -%}
        {%- unless processedBranches contains branchGuid -%}
            {%- if processedBranches != "" -%},{%- endif -%}
    "{{branchGuid}}": {
        "code": "{{row.lv_xbranchcode | escape}}",
        "name": "{{row.lv_xbranchname | escape}}",
        "periods": [
        {%- assign periodsList = "" -%}
        {%- for periodRow in branchPeriodsMapping.results.entities -%}
            {%- if periodRow.branchid == branchGuid -%}
                {%- if periodsList != "" -%},{%- endif -%}
                {{periodRow.lv_periodno}}
                {%- assign periodsList = periodsList | append: "," -%}
                {%- comment -%} Also collect all periods for the "all" entry {%- endcomment -%}
                {%- capture periodMarker -%}|{{periodRow.lv_periodno}}|{%- endcapture -%}
                {%- unless allPeriodsForUser contains periodMarker -%}
                    {%- assign allPeriodsForUser = allPeriodsForUser | append: periodMarker -%}
                {%- endunless -%}
            {%- endif -%}
        {%- endfor -%}
        ]
    }
            {%- assign processedBranches = processedBranches | append: "|" | append: branchGuid | append: "|" -%}
        {%- endunless -%}
    {%- endif -%}
{%- endfor -%}
{%- comment -%} Add special "all" entry for multi-branch managers {%- endcomment -%}
{%- if allPeriodsForUser != "" -%}
    ,
    "all": {
        "code": "ALL_BRANCHES",
        "name": "All Branches",
        "periods": [
        {%- assign allPeriodsList = "" -%}
        {%- assign allPeriodsArray = allPeriodsForUser | split: "|" -%}
        {%- for periodStr in allPeriodsArray -%}
            {%- if periodStr != "" -%}
                {%- if allPeriodsList != "" -%},{%- endif -%}
                {{periodStr}}
                {%- assign allPeriodsList = allPeriodsList | append: "," -%}
            {%- endif -%}
        {%- endfor -%}
        ]
    }
{%- endif -%}
};
{%- else -%}
window.branchPeriodsMapping = {};
console.warn('DEBUG: No branch periods mapping data found');
{%- endif -%}

console.log('Branch Periods Mapping loaded:', window.branchPeriodsMapping);
</script>
{%- endif -%}

